                title,
                style: TextStyleManager.caption.copyWith(
                  color: Theme.of(context).colorScheme.onSurfaceVariant,
                  fontWeight: FontWeight.w500,
                ),
              ),
            ),
            const Text(
              ':  ',
              style: TextStyleManager.caption,
            ),
            Expanded(
              child: Text(
                value,
                style: TextStyleManager.caption.copyWith(
                  fontWeight: FontWeight.w600,
                ),
              ),
            ),
          ],
        ),
        if (child != null) child!,
      ],
    );
  }
}

class _RestrictionBanner extends StatelessWidget {
  const _RestrictionBanner({required this.message});

  final String message;

  @override
  Widget build(BuildContext context) {
    final colorScheme = Theme.of(context).colorScheme;
    return Container(
      width: double.infinity,
      padding: const EdgeInsets.all(12),
      decoration: BoxDecoration(
        color: colorScheme.surfaceContainerHighest.withAlpha(80),
        borderRadius: BorderRadius.circular(8),
      ),
      child: Row(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Icon(Icons.info_outline,
              color: colorScheme.onSurfaceVariant, size: 20),
          const Gap(8),
          Expanded(
            child: Text(
              message,
              style: TextStyleManager.caption.copyWith(
                color: colorScheme.onSurface,
                fontWeight: FontWeight.w600,
              ),
            ),
          ),
        ],
      ),
    );
  }
}

class _BillingWarningBanner extends StatelessWidget {
  const _BillingWarningBanner({required this.billingFailureReason});

  final String billingFailureReason;

  @override
  Widget build(BuildContext context) {
    final colorScheme = Theme.of(context).colorScheme;
    final message = _resolveMessage(context);
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Row(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Icon(
              Icons.warning,
              color: colorScheme.error,
              size: 18,
            ),
            const Gap(8),
            Expanded(
              child: Text(
                message,
                style: TextStyleManager.caption.copyWith(
                  color: colorScheme.error,
                  fontWeight: FontWeight.w600,
                ),
              ),
            ),
          ],
        ),
      ],
    );
  }

  String _resolveMessage(BuildContext context) {
    switch (billingFailureReason) {
      case 'stripe_payment_failed':
        return context.l10n.settings_page__billing_failure_message_stripe;
      case 'apple_payment_failed':
      default:
        return context.l10n.settings_page__billing_failure_message;
    }
  }
}

