class _UsageDetailsSection extends HookConsumerWidget {
  const _UsageDetailsSection({required this.team});

  final Team? team;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    if (team == null) return const SizedBox.shrink();

    final usageFormatter = NumberFormat('#,###');
    final ballUsage = team!.ballUsage;
    final maxBalls = team!.maxBalls;
    final usagePercentage = maxBalls > 0
        ? (ballUsage / maxBalls).clamp(0.0, 1.0)
        : 0.0;

    final aiCoachUsage = team!.aiCoachUsage;
    final maxAiCoach = team!.maxAiCoachCount;
    final aiCoachUsagePercentage = maxAiCoach > 0
        ? (aiCoachUsage / maxAiCoach).clamp(0.0, 1.0)
        : 0.0;

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          'Usage Details',
          style: TextStyleManager.body1.copyWith(
            fontWeight: FontWeight.w600,
          ),
        ),
        const Gap(12),
        Column(
          children: [
            _UsageRow(
              title: 'Ball Analysis',
              currentValue: ballUsage,
              maxValue: maxBalls,
              percentage: usagePercentage,
              formatter: usageFormatter,
            ),
            if (maxAiCoach > 0) ...[
              const Gap(16),
              _UsageRow(
                title: 'AI Coach',
                currentValue: aiCoachUsage,
                maxValue: maxAiCoach,
                percentage: aiCoachUsagePercentage,
                formatter: usageFormatter,
              ),
            ],
          ],
        ),
      ],
    );
  }
}

