class _NextPlanSection extends HookWidget {
  const _NextPlanSection({
    required this.nextTeamPlan,
    required this.formatDateTimeWithSeconds,
  });

  final TeamPlan nextTeamPlan;
  final String Function(DateTime?) formatDateTimeWithSeconds;

  @override
  Widget build(BuildContext context) {
    final planName = usePlanNameFromTeamPlan(nextTeamPlan);

    return _PlanSection(
      icon: Icons.schedule_outlined,
      title: context.l10n.settings_page__next_plan,
      backgroundColor:
          Theme.of(context).colorScheme.secondaryContainer.withAlpha(75),
      child: Column(
        children: [
          _PlanRow(
            title: context.l10n.settings_page__plan,
            value: planName,
          ),
          const Gap(8),
          _PlanRow(
            title: context.l10n.settings_page__valid_period,
            value: (nextTeamPlan.startDate == null &&
                    nextTeamPlan.endDate == null)
                ? context.l10n.settings_page__no_expiration
                : '${formatDateTimeWithSeconds(nextTeamPlan.startDate)} ~ ${formatDateTimeWithSeconds(nextTeamPlan.endDate)}',
          ),
        ],
      ),
    );
  }
}

class _PlanRow extends StatelessWidget {
  const _PlanRow({
    required this.title,
    required this.value,
    this.child,
  });

  final String title;
  final String value;
  final Widget? child;
